import{_ as t,o as e,c as a,U as o}from"./chunks/framework.9adb0f96.js";const _=JSON.parse('{"title":"React Hook底层原理","description":"","frontmatter":{"layout":"blog","title":"React Hook底层原理","date":"2022-08-01T02:20:08.748Z"},"headers":[],"relativePath":"react/react-hook.md","filePath":"react/react-hook.md","lastUpdated":null}'),r={name:"react/react-hook.md"},s=o('<p><strong>好处:</strong> .<br> 1、跨组件复用: 其实 render props / HOC 也是为了复用，相比于它们，Hooks 作为官方的底层 API，最为轻量，而且改造成本小，不会影响原来的组件层次结构和传说中的嵌套地狱；<br> 2、类定义更为复杂:<br> 不同的生命周期会使逻辑变得分散且混乱，不易维护和管理；<br> 时刻需要关注this的指向问题；<br> 代码复用代价高，高阶组件的使用经常会使整个组件树变得臃肿；<br> 3、状态与UI隔离: 正是由于 Hooks 的特性，状态逻辑会变成更小的粒度，并且极容易被抽象成一个自定义 Hooks，组件中的状态和 UI 变得更为清晰和隔离。</p><p><strong>注意:</strong> . 1.避免在 循环/条件判断/嵌套函数 中调用 hooks，保证调用顺序的稳定；<br> 2.只有 函数定义组件 和 hooks 可以调用 hooks，避免在 类组件 或者 普通函数 中调用；<br> 3.不能在useEffect中使用useState，React 会报错提示；<br> 4.类组件不会被替换或废弃，不需要强制改造类组件，两种方式能并存；</p><p><strong>重要钩子</strong> . ##useState . 当调用 useState 的时候，会返回形如 (变量, 函数) 的一个元祖。并且 state 的初始值就是外部调用 useState 的时候，传入的参数。</p><p>工作原理:</p><p>1.初始化 .<br><img src="https://miro.medium.com/max/1280/1*LAZDuAEm7nbcx0vWVKJJ2w.png" alt=""> 2.首次渲染<br><img src="https://miro.medium.com/max/1260/1*8TpWnrL-Jqh7PymLWKXbWg.png" alt=""> 3.重渲染 每次后续渲染，光标都会被重置，并且这些值从数组中读取。 <img src="https://miro.medium.com/max/1254/1*qtwvPWj-K3PkLQ6SzE2u8w.png" alt=""> 4.事件处理 每个 setter 都有一个对其光标位置的引用，因此通过触发对 any 的调用，setter它将更改状态数组中该位置的状态值。 <img src="https://miro.medium.com/max/1260/1*3L8YJnn5eV5ev1FuN6rKSQ.png" alt=""></p><h2 id="游标数组" tabindex="-1">游标数组 <a class="header-anchor" href="#游标数组" aria-label="Permalink to &quot;游标数组&quot;">​</a></h2><p>由数组来实现的“链表”——游标数组。<br> 其优点是可以快速的插入和删除（由于不需要指针式链表的malloc和free等内存操作，所以使用时游标数组可能会比指针式链表还要快一点），缺点则是继承自数组——固定大小。</p><h3 id="为什么不能在循环、判断中使用" tabindex="-1">为什么不能在循环、判断中使用 . <a class="header-anchor" href="#为什么不能在循环、判断中使用" aria-label="Permalink to &quot;为什么不能在循环、判断中使用 .&quot;">​</a></h3><p>如果在条件渲染中使用，会导致重渲染的时候，异常的游标对应，异常的游标对应也会导致调用的setState方法失效</p><h2 id="useeffect" tabindex="-1">useEffect <a class="header-anchor" href="#useeffect" aria-label="Permalink to &quot;useEffect&quot;">​</a></h2><p>作用是副作用，说直白就是某些state或者props变化的时候，需要监听并执行相应的操作。 待完善</p>',11),c=[s];function n(p,i,m,h,l,d){return e(),a("div",null,c)}const f=t(r,[["render",n]]);export{_ as __pageData,f as default};
